<?php
/**
 * Customer Me dashboard shortcode template.
 *
 * @package Banoks_POS
 */

if ( ! defined( 'ABSPATH' ) ) {
    exit;
}

$related_data = isset( $related_data ) && is_array( $related_data ) ? $related_data : array();
$order_items  = isset( $related_data['items'] ) && is_array( $related_data['items'] ) ? $related_data['items'] : array();
$order_logs   = isset( $related_data['logs'] ) && is_array( $related_data['logs'] ) ? $related_data['logs'] : array();

$status_labels = array(
    'pending'          => 'Pending',
    'verifying'        => 'Pending',
    'preparing'        => 'Preparing',
    'ready_for_pickup' => 'Ready for Pickup',
    'delivering'       => 'Delivering',
    'completed'        => 'Completed',
    'cancelled'        => 'Cancelled',
    'rejected'         => 'Rejected',
);

$terminal_statuses = array( 'completed', 'cancelled', 'rejected' );
$active_orders     = array();
$past_orders       = array();

foreach ( (array) $orders as $order ) {
    if ( in_array( $order->order_status, $terminal_statuses, true ) ) {
        $past_orders[] = $order;
    } else {
        $active_orders[] = $order;
    }
}

$render_status_label = function ( $status ) use ( $status_labels ) {
    return isset( $status_labels[ $status ] ) ? $status_labels[ $status ] : ucwords( str_replace( '_', ' ', (string) $status ) );
};

$get_steps = function ( $order ) {
    $is_pickup = ! empty( $order->fulfillment_type ) && 'pickup' === $order->fulfillment_type;

    return $is_pickup
        ? array(
            'pending'          => 'Pending',
            'preparing'        => 'Preparing',
            'ready_for_pickup' => 'Ready',
            'completed'        => 'Completed',
        )
        : array(
            'pending'    => 'Pending',
            'preparing'  => 'Preparing',
            'delivering' => 'Delivering',
            'completed'  => 'Completed',
        );
};

$get_progress_context = function ( $order ) use ( $get_steps ) {
    $status            = isset( $order->order_status ) ? $order->order_status : 'pending';
    $steps             = $get_steps( $order );
    $normalized_status = 'verifying' === $status ? 'pending' : $status;
    $step_keys         = array_keys( $steps );
    $current_index     = array_search( $normalized_status, $step_keys, true );

    if ( false === $current_index ) {
        $current_index = 'completed' === $status ? count( $step_keys ) - 1 : 0;
    }

    return array(
        'current_index' => $current_index,
        'status'        => $status,
        'steps'         => $steps,
        'step_keys'     => $step_keys,
    );
};

$render_order_progress = function ( $order, $modifier = '' ) use ( $get_progress_context ) {
    $context = $get_progress_context( $order );
    $classes = 'banoks-me-progress';
    if ( $modifier ) {
        $classes .= ' ' . $modifier;
    }
    ?>
    <span class="<?php echo esc_attr( $classes ); ?>" aria-label="<?php echo esc_attr( 'Order progress for ' . $order->online_order_id ); ?>">
        <?php foreach ( $context['steps'] as $step_key => $step_label ) : ?>
            <?php
            $step_index = array_search( $step_key, $context['step_keys'], true );
            $is_done    = $step_index <= $context['current_index'];
            $is_current = $step_index === $context['current_index'];
            ?>
            <span class="banoks-me-progress-step <?php echo $is_done ? 'is-done' : ''; ?> <?php echo $is_current ? 'is-current' : ''; ?>">
                <span aria-hidden="true"></span>
                <small><?php echo esc_html( $step_label ); ?></small>
            </span>
        <?php endforeach; ?>
    </span>
    <?php
};

