$render_terminal_status = function ( $status ) {
    $is_completed = 'completed' === $status;
    $classes      = 'banoks-me-terminal-status ' . ( $is_completed ? 'is-completed' : 'is-cancelled' );
    $message      = $is_completed ? 'Order Successfully Delivered' : 'Order Cancelled';
    $icon_label   = $is_completed ? 'Delivered' : 'Cancelled';
    ?>
    <div class="<?php echo esc_attr( $classes ); ?>" role="status" aria-label="<?php echo esc_attr( $icon_label ); ?>">
        <span class="banoks-me-terminal-icon" aria-hidden="true">
            <?php if ( $is_completed ) : ?>
                <svg viewBox="0 0 24 24" focusable="false">
                    <path d="M9.2 16.7 4.9 12.4 3.5 13.8 9.2 19.5 21 7.7 19.6 6.3z"></path>
                </svg>
            <?php else : ?>
                <svg viewBox="0 0 24 24" focusable="false">
                    <path d="M18.3 5.7 12 12l6.3 6.3-1.4 1.4L10.6 13.4 4.3 19.7 2.9 18.3 9.2 12 2.9 5.7 4.3 4.3l6.3 6.3 6.3-6.3z"></path>
                </svg>
            <?php endif; ?>
        </span>
        <strong><?php echo esc_html( $message ); ?></strong>
    </div>
    <?php
};


$render_order_card = function ( $order ) use ( $render_status_label, $render_order_progress ) {
    $status            = isset( $order->order_status ) ? $order->order_status : 'pending';
    $fulfillment_label = ! empty( $order->fulfillment_type ) && 'pickup' === $order->fulfillment_type ? 'Pickup' : 'Delivery';
    ?>
    <button type="button" class="banoks-me-order-card is-<?php echo esc_attr( $status ); ?>" data-banoks-me-order-id="<?php echo esc_attr( $order->id ); ?>" aria-label="<?php echo esc_attr( 'Open order ' . $order->online_order_id ); ?>">
        <span class="banoks-me-order-head">
            <span>
                <strong><?php echo esc_html( $order->online_order_id ); ?></strong>
                <small><?php echo esc_html( wp_date( 'M d, Y g:i A', strtotime( $order->created_at ) ) ); ?></small>
            </span>
            <span class="banoks-me-status is-<?php echo esc_attr( $status ); ?>"><?php echo esc_html( $render_status_label( $status ) ); ?></span>
        </span>

        <?php $render_order_progress( $order, 'is-compact' ); ?>

        <span class="banoks-me-order-foot">
            <small><?php echo esc_html( $fulfillment_label ); ?></small>
            <strong>&#8369;<?php echo esc_html( number_format( floatval( $order->total_amount ), 2 ) ); ?></strong>
        </span>
    </button>
    <?php
};

$render_order_detail = function ( $order ) use ( $order_items, $order_logs, $render_status_label, $render_order_progress, $render_tracking_animation, $render_terminal_status ) {
    $status            = isset( $order->order_status ) ? $order->order_status : 'pending';
    $items             = isset( $order_items[ $order->id ] ) ? $order_items[ $order->id ] : array();
    $logs              = isset( $order_logs[ $order->id ] ) ? $order_logs[ $order->id ] : array();
    $fulfillment_label = ! empty( $order->fulfillment_type ) && 'pickup' === $order->fulfillment_type ? 'Pickup' : 'Delivery';
    $payment_label     = ! empty( $order->payment_method ) ? strtoupper( str_replace( '_', ' ', $order->payment_method ) ) : 'Payment';
    ?>
    <article class="banoks-me-order-detail" data-banoks-me-order-detail="<?php echo esc_attr( $order->id ); ?>" hidden>
        <header class="banoks-me-detail-head">
            <button type="button" data-banoks-me-orders-back>Back</button>
            <div>
                <h2><?php echo esc_html( $order->online_order_id ); ?></h2>
            </div>
        </header>

        <?php
        if ( in_array( $status, array( 'completed', 'cancelled', 'rejected' ), true ) ) {
            $render_terminal_status( $status );
        } else {
            $render_tracking_animation();
        }
        ?>

        <section class="banoks-me-detail-card">
            <div class="banoks-me-detail-status-row">
                <span class="banoks-me-status is-<?php echo esc_attr( $status ); ?>"><?php echo esc_html( $render_status_label( $status ) ); ?></span>
                <strong>&#8369;<?php echo esc_html( number_format( floatval( $order->total_amount ), 2 ) ); ?></strong>
            </div>
            <?php $render_order_progress( $order, 'is-detail' ); ?>
        </section>

        <section class="banoks-me-detail-card">
            <h3>Order Info</h3>
            <dl class="banoks-me-detail-list">
                <div>
                    <dt>Date</dt>
                    <dd><?php echo esc_html( wp_date( 'M d, Y g:i A', strtotime( $order->created_at ) ) ); ?></dd>
                </div>
                <div>
                    <dt>Type</dt>
                    <dd><?php echo esc_html( $fulfillment_label ); ?></dd>
                </div>
                <div>
                    <dt>Payment</dt>
                    <dd><?php echo esc_html( $payment_label ); ?> - <?php echo esc_html( ucwords( str_replace( '_', ' ', (string) $order->payment_status ) ) ); ?></dd>
                </div>
                <?php if ( ! empty( $order->delivery_address ) ) : ?>
                    <div>
                        <dt>Address</dt>
                        <dd><?php echo esc_html( $order->delivery_address ); ?></dd>
                    </div>
                <?php endif; ?>
                <?php if ( ! empty( $order->driver_name ) || ! empty( $order->driver_contact ) ) : ?>
                    <div>
                        <dt>Rider</dt>
                        <dd><?php echo esc_html( trim( $order->driver_name . ' ' . $order->driver_contact ) ); ?></dd>
                    </div>
                <?php endif; ?>
                <?php if ( ! empty( $order->notes ) ) : ?>
                    <div>
                        <dt>Notes</dt>
                        <dd><?php echo esc_html( $order->notes ); ?></dd>
                    </div>
                <?php endif; ?>
            </dl>
        </section>

        <section class="banoks-me-detail-card">
            <h3>Items</h3>
            <?php if ( empty( $items ) ) : ?>
                <p class="banoks-me-detail-muted">No item details available.</p>
            <?php else : ?>
                <div class="banoks-me-detail-items">
                    <?php foreach ( $items as $item ) : ?>
                        <div>
                            <span>
                                <strong><?php echo esc_html( $item->product_name ); ?></strong>
                                <small>x<?php echo esc_html( absint( $item->quantity ) ); ?> at &#8369;<?php echo esc_html( number_format( floatval( $item->price ), 2 ) ); ?></small>
                            </span>
                            <strong>&#8369;<?php echo esc_html( number_format( floatval( $item->subtotal ), 2 ) ); ?></strong>
                        </div>
                    <?php endforeach; ?>
                </div>
            <?php endif; ?>
        </section>

        <section class="banoks-me-detail-card">
            <h3>Payment Summary</h3>
            <dl class="banoks-me-total-list">
                <div>
                    <dt>Subtotal</dt>
                    <dd>&#8369;<?php echo esc_html( number_format( floatval( $order->subtotal ), 2 ) ); ?></dd>
                </div>
                <div>
                    <dt>Delivery Fee</dt>
                    <dd>&#8369;<?php echo esc_html( number_format( floatval( $order->delivery_fee ), 2 ) ); ?></dd>
                </div>
                <div>
                    <dt>Total Amount</dt>
                    <dd>&#8369;<?php echo esc_html( number_format( floatval( $order->total_amount ), 2 ) ); ?></dd>
                </div>
            </dl>
        </section>

        <?php if ( ! empty( $logs ) ) : ?>
            <section class="banoks-me-detail-card">
                <h3>Status History</h3>
                <div class="banoks-me-log-list">
                    <?php foreach ( $logs as $log ) : ?>
                        <div>
                            <strong><?php echo esc_html( $render_status_label( $log->new_status ) ); ?></strong>
                            <span><?php echo esc_html( wp_date( 'M d, Y g:i A', strtotime( $log->created_at ) ) ); ?></span>
                            <?php if ( ! empty( $log->note ) ) : ?>
                                <p><?php echo esc_html( $log->note ); ?></p>
                            <?php endif; ?>
                        </div>
                    <?php endforeach; ?>
                </div>
            </section>
        <?php endif; ?>
    </article>
    <?php
};
?>
