                <div data-banoks-me-orders-list>
                    <header class="banoks-me-panel-head">
                        <button type="button" data-banoks-me-back>Back</button>
                        <div>
                            <h2>My Orders</h2>
                        </div>
                        <strong><?php echo esc_html( count( $active_orders ) ); ?> active</strong>
                    </header>

                    <?php if ( empty( $orders ) ) : ?>
                        <div class="banoks-me-empty">
                            <strong>No online orders yet.</strong>
                            <p>Your active and past orders will appear here.</p>
                        </div>
                    <?php else : ?>
                        <?php if ( ! empty( $active_orders ) ) : ?>
                            <div class="banoks-me-order-group">
                                <h3>Active Orders</h3>
                                <?php foreach ( $active_orders as $order ) : ?>
                                    <?php $render_order_card( $order ); ?>
                                <?php endforeach; ?>
                            </div>
                        <?php endif; ?>

                        <?php if ( ! empty( $past_orders ) ) : ?>
                            <div class="banoks-me-order-group">
                                <h3>Past Orders</h3>
                                <?php foreach ( array_slice( $past_orders, 0, 8 ) as $order ) : ?>
                                    <?php $render_order_card( $order ); ?>
                                <?php endforeach; ?>
                            </div>
                        <?php endif; ?>
                    <?php endif; ?>
                </div>

                <div data-banoks-me-order-details>
                    <?php foreach ( (array) $orders as $order ) : ?>
                        <?php $render_order_detail( $order ); ?>
                    <?php endforeach; ?>
                </div>
            </section>
        </div>
